import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.BGHOrOyn.js";const n="/gitbook-personnal-docs/assets/network_regional_subnet.D49NZeS9.svg",m=JSON.parse('{"title":"Networking Overview","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/networking/oracle-vcn-docs/networking-overview.md","filePath":"software-engineering/networking/oracle-vcn-docs/networking-overview.md"}'),s={name:"software-engineering/networking/oracle-vcn-docs/networking-overview.md"};function i(c,e,l,h,d,u){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="networking-overview" tabindex="-1">Networking Overview <a class="header-anchor" href="#networking-overview" aria-label="Permalink to &quot;Networking Overview&quot;">​</a></h1><p>When you work with Oracle Cloud Infrastructure, one of the first steps is to set up a Virtual Cloud Network (VCN) for cloud resources. This topic gives you an overview of Oracle Cloud Infrastructure Networking components and typical scenarios for using a VCN.</p><blockquote><p><strong>Note</strong></p><p>Watch a <a href="https://apexapps.oracle.com/pls/apex/f?p=44785:265:0:::265:P265_CONTENT_ID:32072" target="_blank" rel="noreferrer">video introduction</a> to the service.</p></blockquote><h2 id="networking-components" tabindex="-1">Networking Components <a class="header-anchor" href="#networking-components" aria-label="Permalink to &quot;Networking Components&quot;">​</a></h2><p>The Networking service uses virtual versions of traditional network components you might already be familiar with:</p><p>Virtual Cloud Network (VCN)<br> A virtual, private network that you set up in Oracle data centers. It closely resembles a traditional network, with firewall rules and specific types of communication gateways that you can decide to use. A VCN resides in a single Oracle Cloud Infrastructure region and covers one or more CIDR blocks (IPv4 and IPv6, if enabled). See <a href="./networking-overview.html#Allowed">Allowed VCN Size and Address Ranges</a>. The terms <em>virtual cloud network</em>, <em>VCN, and cloud network</em> are used interchangeably in this documentation. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/VCNs.htm" target="_blank" rel="noreferrer">VCNs and Subnets</a>.</p><p>Subnets<br> Subdivisions you define in a VCN (for example, 10.0.0.0/24, 10.0.1.0/24, or 2001:DB8::/64). Subnets contain virtual network interface cards (VNICs), which attach to Compute instances. Each subnet consists of a contiguous range of IP addresses (for IPv4 and IPv6, if enabled) that don&#39;t overlap with other subnets in the VCN. You can set a subnet to exist either in a single <strong>availability domain</strong> or across an entire region (regional subnets are recommended). Subnets act as a unit of configuration within the VCN: All VNICs in a particular subnet use the same route table, security lists, and DHCP options. You can define a subnet as either public or private when you create it. Private means VNICs in the subnet can&#39;t have public IPv4 addresses and internet communication with IPv6 endpoints is prohibited. Public means VNICs in the subnet can have public IPv4 addresses and internet communication is allowed with IPv6 endpoints. See <a href="./networking-overview.html#Private">Access to the Internet</a>.</p><p>VNIC<br> A virtual network interface card (VNIC), which attaches to a Compute instance and resides in a subnet to enable a connection to the subnet&#39;s VCN. A VNIC is the component the Compute instance uses to connect with endpoints inside and outside the VCN. Each Compute instance has a primary VNIC that&#39;s created during Compute instance creation and can&#39;t be removed. You can add secondary VNICs to an existing Compute instance (in the same availability domain as the primary VNIC), and remove them as needed. Each secondary VNIC can be in a subnet in the same VCN as the primary VNIC, or in a different subnet either in the same VCN or a different one. However, all the VNICs must be in the same availability domain as the Compute instance. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVNICs.htm" target="_blank" rel="noreferrer">Virtual Network Interface Cards (VNICs)</a>. A VNIC attached to a Compute instance and residing in an IPv6-enabled subnet can optionally be assigned an IPv6 address.</p><p>Private IP<br> A private IPv4 address and related information for addressing a Compute instance (for example, a hostname for DNS). Each VNIC has a primary private IP, and you can add and remove secondary private IPs. The primary private IP address on a Compute instance doesn&#39;t change during the Compute instance&#39;s lifetime and can&#39;t be removed. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingIPaddresses.htm" target="_blank" rel="noreferrer">Private IP Addresses</a>.</p><p>Public IP<br> A public IPv4 address and related information. You can optionally assign a public IP to Compute instances or other resources that have a private IP. Public IPs can be either <em>ephemeral</em> or <em>reserved</em>. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingpublicIPs.htm" target="_blank" rel="noreferrer">Public IP Addresses</a>.</p><p>IPv6<br> An IPv6 address and related information. IPv6 addressing is supported for all commercial and government regions. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/ipv6.htm" target="_blank" rel="noreferrer">IPv6 Addresses</a>.</p><p>Dynamic Routing Gateway (DRG)<br> An optional virtual router that you can attach to one or many VCNs. It provides a path for <em>private</em> network traffic between a VCN and an on-premises network. You can use it with other Networking components and a router in an on-premises network to establish a connection by way of Site-to-Site VPN or Oracle Cloud Infrastructure FastConnect. It can also provide a path for private network traffic between a VCN and another VCN in the same region or in a different region. For more information, see <a href="./networking-overview.html#on_prem_access">Access to Your On-Premises Network</a>, <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingDRGs.htm" target="_blank" rel="noreferrer">Dynamic Routing Gateways</a>, <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenario_d.htm" target="_blank" rel="noreferrer">Local VCN Peering Through an Upgraded DRG</a> and <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenario_e.htm" target="_blank" rel="noreferrer">Remote VCN Peering through an Upgraded DRG</a>.</p><p>Internet Gateway<br> An optional virtual router that you can add to a VCN for direct internet access. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingIGs.htm" target="_blank" rel="noreferrer">Internet Gateway</a> and <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenarioa.htm" target="_blank" rel="noreferrer">Scenario A: Public Subnet</a>.</p><p>Network Address Translation (NAT) Gateway<br> Another optional virtual router that you can add to a VCN. It gives cloud resources without public IP addresses access to the internet without exposing those resources to incoming internet connections. For more information, see <a href="./networking-overview.html#Public">Public vs. Private Subnets</a> and <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/NATgateway.htm" target="_blank" rel="noreferrer">NAT Gateway</a>.</p><p>Service Gateway<br> Another optional virtual router that you can add to a VCN. It provides a path for <em>private</em> network traffic between a VCN and <a href="https://www.oracle.com/cloud/networking/service-gateway/service-gateway-supported-services/" target="_blank" rel="noreferrer">supported services in the Oracle Services Network</a> (examples: Oracle Cloud Infrastructure Object Storage and Autonomous AI Database). For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/servicegateway.htm#Access_to_Oracle_Services_Service_Gateway" target="_blank" rel="noreferrer">Access to Oracle Services: Service Gateway</a>.</p><p>Local Peering Gateway (LPG)<br> Another optional virtual router that you can add to a VCN. It lets you peer one VCN with another VCN in the same region. <em>Peering</em> means the VCNs communicate using private IP addresses, without the traffic traversing the internet or routing through an on-premises network. A VCN must have a separate LPG for each peering it establishes. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/localVCNpeering.htm" target="_blank" rel="noreferrer">Local VCN Peering using Local Peering Gateways</a>.</p><p>Remote Peering Connection (RPC)<br> A component that you can add to a DRG. It lets you peer one VCN with another VCN in a <em>different</em> region. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenario_e.htm" target="_blank" rel="noreferrer">Remote VCN Peering through an Upgraded DRG</a>.</p><p>Route Tables<br> Virtual route tables for a VCN. They have rules to route traffic from subnets to destinations outside the VCN by way of gateways or specially configured Compute instances. A VCN comes with an empty default route table, and you can add custom route tables. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingroutetables.htm" target="_blank" rel="noreferrer">VCN Route Tables</a>.</p><p>Security Rules<br> Virtual firewall rules for a VCN. Ingress and egress rules specify the types of traffic (protocol and port) allowed in and out of the Compute instances. You can decide whether a particular rule is stateful or stateless. For example, you can allow incoming SSH traffic from anywhere to a set of Compute instances by setting up a stateful ingress rule with source CIDR 0.0.0.0/0, and destination TCP port 22. To implement security rules, you can use <em>network security groups</em> or <em>security lists</em>. A network security group consists of a set of security rules that apply only to the resources in that group. Contrast this with a security list, where the rules apply to all the resources in any subnet that uses the list. A VCN comes with a default security list with default security rules. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/securityrules.htm" target="_blank" rel="noreferrer">Security Rules</a>.</p><p>DHCP Options<br> Configuration information automatically provided to the Compute instances when they boot up. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingDHCP.htm" target="_blank" rel="noreferrer">DHCP Options</a>.</p><p>CIDR Notation<br> A compact method for specifying IP addresses or address ranges and network masks. For example, using IPv4 a private IP address range of 10.0.0.0/24 represents all addresses between 10.0.0.0 and 10.0.0.255. The /24 represents a subnet mask of 255.255.255.0 because the first 24 bits are masked. IPv6 uses similar notation for address blocks. For more information, see <a href="https://datatracker.ietf.org/doc/html/rfc1817" target="_blank" rel="noreferrer">RFC1817</a> and <a href="https://datatracker.ietf.org/doc/html/rfc1519" target="_blank" rel="noreferrer">RFC1519</a>.</p><h2 id="allowed-vcn-size-and-address-ranges" tabindex="-1">Allowed VCN Size and Address Ranges <a class="header-anchor" href="#allowed-vcn-size-and-address-ranges" aria-label="Permalink to &quot;Allowed VCN Size and Address Ranges&quot;">​</a></h2><p>A VCN covers one or more IPv4 CIDR blocks or IPv6 prefixes. The allowable VCN size range is /16 to /30. Example: 10.0.0.0/16. The Networking service reserves the first two IP addresses and the last one in each subnet&#39;s CIDR.</p><p>You can enable IPv6 for VCNs when you create them, or you can enable IPv6 on existing IPv4-only VCNs. If you decide to use an Oracle-allocated IPv6 prefix, you always receive a /56. Alternately, you can <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/BYOIP.htm" target="_blank" rel="noreferrer">import your own BYOIP IPv6 prefix</a> from which you can assign any prefix of /64 or larger to a VCN, or you can assign a ULA prefix of /64 or larger. GUA ranges can be up to 2000::/3 and ULA ranges can be up to fc00::/7. IPv6 subnets are always /64 in size.</p><p>For a VCN, we recommend using the private IP address ranges specified in <a href="https://tools.ietf.org/html/rfc1918" target="_blank" rel="noreferrer">RFC 1918</a> (the RFC recommends 10.0/8 or 172.16/12 but Oracle doesn&#39;t support those sizes so use 10.0/16, 172.16/16, and 192.168/16). However, you can use a publicly routable range. Regardless, this documentation uses the term <em>private IP address</em> when referring to IP addresses in a VCN&#39;s CIDR. Address ranges that are disallowed are described in <a href="./networking-overview.html#Reserved">IP Addresses Reserved for Use by Oracle</a>. For IPv6-enabled VCNs, Oracle can either allocate a global unicast address /56 prefix or you can create a VCN with a BYOIPv6 prefix.</p><p>The VCN&#39;s CIDR blocks must not overlap with each other, with CIDRs in a connected on-premises network, or with the CIDRs of <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/VCNpeering.htm" target="_blank" rel="noreferrer">another VCN you peer with</a>. The subnets in a particular VCN must not overlap with each other. For reference, here&#39;s a <a href="http://www.ipaddressguide.com/cidr" target="_blank" rel="noreferrer">CIDR calculator</a>.</p><p>IPv6 addressing is supported for all commercial and government regions. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/ipv6.htm" target="_blank" rel="noreferrer">IPv6 Addresses</a>.</p><h2 id="availability-domains-and-vcns" tabindex="-1">Availability Domains and VCNs <a class="header-anchor" href="#availability-domains-and-vcns" aria-label="Permalink to &quot;Availability Domains and VCNs&quot;">​</a></h2><p>A VCN resides in a single Oracle Cloud Infrastructure region. A region can have several availability domains to provide isolation and redundancy. For more information, see <a href="https://docs.oracle.com/iaas/Content/General/Concepts/regions.htm" target="_blank" rel="noreferrer">Regions and Availability Domains</a>.</p><p>Originally subnets were designed to cover only one availability domain (AD) in a region. They were all <em>AD-specific</em>, which means the subnet&#39;s resources were required to reside in a particular availability domain. Now subnets can be either AD-specific or <em>regional</em>. You select the type when you create the subnet. Both types of subnets can coexist in the same VCN. In the following diagram, subnets 1 to 3 are AD-specific, and subnet 4 is regional.</p><p><a href="https://docs.oracle.com/en-us/iaas/Content/Network/Images/network_regional_subnet.svg" target="_blank" rel="noreferrer"><img src="'+n+'" alt="This image shows a VCN with a regional subnet and three AD-specific subnets."></a></p><p>Aside from the removal of the AD constraint, regional subnets behave the same as AD-specific subnets. We recommend using regional subnets because they&#39;re more flexible. They make it easier to efficiently divide a VCN into subnets while also designing for availability domain failure.</p><p>When you create a resource such as a Compute instance, you decide which availability domain the resource is in. From a virtual networking standpoint, you must also decide which VCN and subnet the instance is in. You can select either a regional subnet, or an AD-specific subnet that matches the AD you chose for the instance.</p><h2 id="default-components-that-come-with-a-vcn" tabindex="-1">Default Components that Come With a VCN <a class="header-anchor" href="#default-components-that-come-with-a-vcn" aria-label="Permalink to &quot;Default Components that Come With a VCN&quot;">​</a></h2><p>A VCN automatically comes with these default components:</p><ul><li>Default <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingroutetables.htm" target="_blank" rel="noreferrer">route table</a>, with no route rules</li><li>Default <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/securitylists.htm#Default" target="_blank" rel="noreferrer">security list</a>, with default security rules</li><li>Default <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingDHCP.htm" target="_blank" rel="noreferrer">set of DHCP options</a>, with default values</li></ul><p>You can&#39;t delete these default components. However, you can change their contents (for example, the rules in the default security list). You can also create custom versions of each kind of component in a VCN. Limits exist as to how many you can create and the maximum number of rules. For more information, see <a href="https://docs.oracle.com/iaas/Content/General/Concepts/servicelimits.htm" target="_blank" rel="noreferrer">Limits by Service</a>.</p><p>Each subnet always has these components associated with it:</p><ul><li>One route table</li><li>One or more security lists (for the maximum number, see <a href="https://docs.oracle.com/iaas/Content/General/Concepts/servicelimits.htm" target="_blank" rel="noreferrer">Limits by Service</a>)</li><li>One set of DHCP options</li></ul><p>During subnet creation, you can decide which route table, security list, and set of DHCP options the subnet uses. If you don&#39;t specify a particular component, the subnet automatically uses the VCN&#39;s default component. You can <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/edit_subnet.htm" target="_blank" rel="noreferrer">change which components the subnet uses</a> at any time.</p><blockquote><p><strong>Note</strong></p><p>Security lists are one way to control traffic in and out of the VCN&#39;s resources. You can also use <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/networksecuritygroups.htm" target="_blank" rel="noreferrer">network security groups</a>.</p></blockquote><h2 id="connectivity-choices" tabindex="-1">Connectivity Choices <a class="header-anchor" href="#connectivity-choices" aria-label="Permalink to &quot;Connectivity Choices&quot;">​</a></h2><p>You can control whether subnets are public or private, and whether instances get public IP addresses. You can set up a VCN to have access to the internet if required. You can also privately connect a VCN to public Oracle Cloud Infrastructure services such as Object Storage, to an on-premises network, or to another VCN.</p><h3 id="public-vs-private-subnets" tabindex="-1">Public vs. Private Subnets <a class="header-anchor" href="#public-vs-private-subnets" aria-label="Permalink to &quot;Public vs. Private Subnets&quot;">​</a></h3><p>When you create a subnet, by default it&#39;s considered public, which means instances in that subnet are allowed to have public IPv4 addresses and internet communication is permitted with IPv6 endpoints. Whoever launches the instance chooses whether it has a public IPv4 address or specifies whether an IPv6 address from the allocated prefix will be assigned. You can override that behavior when creating the subnet and request that it be private, which disallows the use of public IPv4 addresses and internet communication with IPv6 endpoints. Network administrators can therefore ensure that instances in the subnet have no internet access, even if the VCN has a working internet gateway, and security rules and firewall rules allow the traffic.</p><h3 id="how-ip-addresses-are-assigned" tabindex="-1">How IP Addresses Are Assigned <a class="header-anchor" href="#how-ip-addresses-are-assigned" aria-label="Permalink to &quot;How IP Addresses Are Assigned&quot;">​</a></h3><p>Each instance has a primary VNIC that&#39;s created during instance launch and cannot be removed. You can add <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVNICs.htm" target="_blank" rel="noreferrer">secondary VNICs</a> to an existing instance (in the same availability domain as the primary VNIC) and remove them as you like.</p><p>Every VNIC has a private IP address from the associated subnet&#39;s CIDR. You can choose the particular IP address (during instance launch or secondary VNIC creation), or Oracle can choose it for you. The private IP address does not change during the lifetime of the instance and cannot be removed. You can also add <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingIPaddresses.htm" target="_blank" rel="noreferrer">secondary private IPv4 addresses</a> or secondary IPv6 addresses to a VNIC.</p><p>If the VNIC is in a public subnet, then each private IP on that VNIC can have a <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingpublicIPs.htm" target="_blank" rel="noreferrer">public IPv4 address or IPv6 address</a> assigned to it at your discretion. For IPv4, Oracle chooses the particular IP address. For IPv6, you can specify the IP address. There are two types of public IPs: <em>ephemeral</em> and <em>reserved</em>. An ephemeral public IP exists only for the lifetime of the private IP it&#39;s assigned to. In contrast, a reserved public IP exists as long as you want it to. You maintain a pool of reserved public IPs and allocate them to your instances at your discretion. You can move them from resource to resource in a region as you need to.</p><h3 id="access-to-the-internet" tabindex="-1">Access to the Internet <a class="header-anchor" href="#access-to-the-internet" aria-label="Permalink to &quot;Access to the Internet&quot;">​</a></h3><p>There are two optional gateways (virtual routers) that you can add to your VCN depending on the type of internet access you need:</p><ul><li>Internet gateway: For resources with public IP addresses that need to be reached from the internet (example: a web server) or need to initiate connections to the internet.</li><li>NAT gateway: For resources without public IP addresses that need to initiate connections to the internet (example: for software updates) but need to be protected from inbound connections from the internet.</li></ul><p>Just having an internet gateway alone does not expose the instances in the VCN&#39;s subnets directly to the internet. The following requirements must also be met:</p><ul><li>The <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingIGs.htm" target="_blank" rel="noreferrer">internet gateway</a> must be enabled (by default, the internet gateway is enabled upon creation).</li><li>The subnet must be <a href="./networking-overview.html#Public">public</a>.</li><li>The subnet must have a <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingroutetables.htm" target="_blank" rel="noreferrer">route rule</a> that directs traffic to the internet gateway.</li><li>The subnet must have <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/securitylists.htm" target="_blank" rel="noreferrer">security list rules</a> that allow the traffic (and each instance&#39;s firewall must allow the traffic).</li><li>The instance must have a <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingpublicIPs.htm" target="_blank" rel="noreferrer">public IP address</a>.</li></ul><blockquote><p><strong>Note</strong></p><p>To access public services such as Object Storage from your VCN without the traffic going over the internet, use a <a href="./networking-overview.html#service_gateway">service gateway</a>.</p><p>Traffic through an internet gateway between a VCN and a public IP address that is part of Oracle Cloud Infrastructure (such as Object Storage) is routed without being sent over the internet.</p></blockquote><p>You can also give a subnet indirect access to the internet by setting up an internet proxy in your on-premises network and then connecting that network to your VCN by way of a DRG. For more information, see <a href="./networking-overview.html#on_prem_access">Access to Your On-Premises Network</a>.</p><h3 id="access-to-public-oracle-cloud-infrastructure-services" tabindex="-1">Access to Public Oracle Cloud Infrastructure Services <a class="header-anchor" href="#access-to-public-oracle-cloud-infrastructure-services" aria-label="Permalink to &quot;Access to Public Oracle Cloud Infrastructure Services&quot;">​</a></h3><p>You can use a service gateway with your VCN to enable private access to public Oracle Cloud Infrastructure services such as Object Storage. For example, DB Systems in a private subnet in your VCN can back up data to Object Storage without needing public IP addresses or access to the internet. No internet gateway or NAT is required. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/servicegateway.htm#Access_to_Oracle_Services_Service_Gateway" target="_blank" rel="noreferrer">Access to Oracle Services: Service Gateway</a>.</p><h3 id="access-to-your-on-premises-network" tabindex="-1">Access to Your On-Premises Network <a class="header-anchor" href="#access-to-your-on-premises-network" aria-label="Permalink to &quot;Access to Your On-Premises Network&quot;">​</a></h3><p>There are two ways to connect your on-premises network to Oracle Cloud Infrastructure:</p><ul><li><a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingIPsec.htm" target="_blank" rel="noreferrer">Site-to-Site VPN:</a> Offers multiple IPSec tunnels between your existing network&#39;s edge and your VCN, by way of a <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingDRGs.htm" target="_blank" rel="noreferrer">DRG</a> that you create and attach to your VCN.</li><li><a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/fastconnect.htm" target="_blank" rel="noreferrer">Oracle Cloud Infrastructure FastConnect:</a> Offers a private connection between your existing network&#39;s edge and Oracle Cloud Infrastructure. Traffic does not traverse the internet. Both private peering and public peering are supported. That means your on-premises hosts can access private IPv4 or IPv6 addresses in your VCN as well as regional public IPv4 or IPv6 addresses in Oracle Cloud Infrastructure (for example, Object Storage or public <a href="https://docs.oracle.com/iaas/Content/Balance/Concepts/balanceoverview.htm" target="_blank" rel="noreferrer">load balancers</a> in your VCN).</li></ul><p>You can use one or both types of the preceding connections. If you use both, you can use them simultaneously, or in a redundant configuration. These connections come to your VCN by way of a single DRG that you create and attach to your VCN. Without that DRG attachment and a route rule for the DRG, traffic does not flow between your VCN and on-premises network. At any time, you can detach the DRG from your VCN but maintain all the remaining components that form the rest of the connection. You could then reattach the DRG again, or attach it to another VCN.</p><h3 id="access-to-another-vcn" tabindex="-1">Access to Another VCN <a class="header-anchor" href="#access-to-another-vcn" aria-label="Permalink to &quot;Access to Another VCN&quot;">​</a></h3><p>You can connect your VCN to another VCN over a private connection that doesn&#39;t require the traffic to traverse the internet. In general, this type of connection is referred to as <em>VCN peering</em>. Each VCN must have specific components to enable peering. The VCNs must also have specific IAM policies, route rules, and security rules that permit the connection to be made and the wanted network traffic to flow over the connection. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/VCNpeering.htm" target="_blank" rel="noreferrer">Access to Other VCNs: Peering</a>.</p><h3 id="connection-to-microsoft-azure" tabindex="-1">Connection to Microsoft Azure <a class="header-anchor" href="#connection-to-microsoft-azure" aria-label="Permalink to &quot;Connection to Microsoft Azure&quot;">​</a></h3><p>Oracle and Microsoft have created a cross-cloud connection between Oracle Cloud Infrastructure and Microsoft Azure in certain regions. This connection lets you set up cross-cloud workloads without the traffic between the clouds going over the internet. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/azure.htm" target="_blank" rel="noreferrer">Interconnect for Azure</a>.</p><h3 id="connection-to-other-clouds-with-libreswan" tabindex="-1">Connection to Other Clouds with Libreswan <a class="header-anchor" href="#connection-to-other-clouds-with-libreswan" aria-label="Permalink to &quot;Connection to Other Clouds with Libreswan&quot;">​</a></h3><p>You can connect your VCN to another cloud provider by using Site-to-Site VPN with a <a href="https://libreswan.org/" target="_blank" rel="noreferrer">Libreswan</a> VM as the customer-premises equipment (CPE). For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/libreswan.htm" target="_blank" rel="noreferrer">Access to Other Clouds with Libreswan</a>.</p><h2 id="networking-scenarios" tabindex="-1">Networking Scenarios <a class="header-anchor" href="#networking-scenarios" aria-label="Permalink to &quot;Networking Scenarios&quot;">​</a></h2><p>This documentation includes a few basic networking scenarios to help you understand the Networking service and how the components work together in general. See these topics:</p><ul><li><a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenarioa.htm" target="_blank" rel="noreferrer">Scenario A: Public Subnet</a></li><li><a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenariob.htm" target="_blank" rel="noreferrer">Scenario B: Private Subnet with a VPN</a></li><li><a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenarioc.htm" target="_blank" rel="noreferrer">Scenario C: Public and Private Subnets with a VPN</a></li></ul><h3 id="transit-routing" tabindex="-1">Transit Routing <a class="header-anchor" href="#transit-routing" aria-label="Permalink to &quot;Transit Routing&quot;">​</a></h3><p>Scenarios A–C show an on-premises network connected to one or more VCNs by way of a DRG and <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/fastconnect.htm" target="_blank" rel="noreferrer">FastConnect</a> or <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingIPsec.htm" target="_blank" rel="noreferrer">Site-to-Site VPN</a>, and accessing only the resources in those VCNs.</p><p>The following advanced routing scenarios give an on-premises network access beyond the resources in the connected VCN. Traffic travels from an on-premises network to the DRG, and then <em>transits through</em> the DRG to its destination. See these topics:</p><ul><li><a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/transitrouting.htm" target="_blank" rel="noreferrer">Transit Routing inside a hub VCN</a>: An on-premises network has access to several VCNs in the same region over a single FastConnect private virtual circuit or Site-to-Site VPN. The DRG and attached VCNs are in a hub-and-spoke topology, with the on-premises network connected to the DRG which acts as the hub. The spoke VCNs are peered.</li><li><a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/transitroutingoracleservices.htm" target="_blank" rel="noreferrer">Private Access to Oracle Services</a>: An on-premises network has private access to Oracle services in the <a href="https://www.oracle.com/cloud/networking/service-gateway/service-gateway-supported-services/" target="_blank" rel="noreferrer">Oracle Services Network</a> by way of a connected VCN and the VCN&#39;s service gateway. The traffic doesn&#39;t go over the internet.</li></ul><h2 id="regions-and-availability-domains" tabindex="-1">Regions and Availability Domains <a class="header-anchor" href="#regions-and-availability-domains" aria-label="Permalink to &quot;Regions and Availability Domains&quot;">​</a></h2><p>A VCN resides in a single Oracle Cloud Infrastructure region. Each subnet resides in a single availability domain (AD). Availability domains are designed to provide isolation and redundancy in the VCN, as illustrated in <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenariob.htm" target="_blank" rel="noreferrer">Scenario B</a> and <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/scenarioc.htm" target="_blank" rel="noreferrer">Scenario C</a> mentioned earlier. For example, you could set up a primary set of subnets in a single AD, and then set up a duplicate set of subnets in a secondary AD. The two ADs are isolated from each other in the Oracle data centers, so if one fails, you can easily switch over to the other AD. For more information, see <a href="https://docs.oracle.com/iaas/Content/General/Concepts/regions.htm" target="_blank" rel="noreferrer">Regions and Availability Domains</a>.</p><h2 id="public-ip-address-ranges" tabindex="-1">Public IP Address Ranges <a class="header-anchor" href="#public-ip-address-ranges" aria-label="Permalink to &quot;Public IP Address Ranges&quot;">​</a></h2><p>For a list of Oracle Cloud Infrastructure public IP ranges, see <a href="https://docs.oracle.com/iaas/Content/General/Concepts/addressranges.htm" target="_blank" rel="noreferrer">IP Address Ranges</a>.</p><h2 id="ip-addresses-reserved-for-use-by-oracle" tabindex="-1">IP Addresses Reserved for Use by Oracle <a class="header-anchor" href="#ip-addresses-reserved-for-use-by-oracle" aria-label="Permalink to &quot;IP Addresses Reserved for Use by Oracle&quot;">​</a></h2><p>Certain IP addresses are reserved for Oracle Cloud Infrastructure use and can&#39;t be used in an address numbering scheme.</p><h3 id="_169-254-0-0-16" tabindex="-1">169.254.0.0/16 <a class="header-anchor" href="#_169-254-0-0-16" aria-label="Permalink to &quot;169.254.0.0/16&quot;">​</a></h3><p>These addresses are used for iSCSI connections to the boot and block volumes, instance metadata, and other services.</p><h3 id="class-d-and-class-e" tabindex="-1">Class D and Class E <a class="header-anchor" href="#class-d-and-class-e" aria-label="Permalink to &quot;Class D and Class E&quot;">​</a></h3><p>All addresses from 224.0.0.0 to 239.255.255.255 (Class D) are prohibited for use in a VCN; they&#39;re reserved for multicast address assignments in the IP standards. See <a href="https://tools.ietf.org/html/rfc3171" target="_blank" rel="noreferrer">RFC 3171</a> for details.</p><p>All addresses from 240.0.0.0 to 255.255.255.255 (Class E) are prohibited for use in a VCN; they&#39;re reserved for future use in the IP standards. See <a href="https://tools.ietf.org/html/rfc1112" target="_blank" rel="noreferrer">RFC 1112, Section 4</a> for details.</p><h3 id="three-ip-addresses-in-each-subnet" tabindex="-1">Three IP Addresses in Each Subnet <a class="header-anchor" href="#three-ip-addresses-in-each-subnet" aria-label="Permalink to &quot;Three IP Addresses in Each Subnet&quot;">​</a></h3><p>These addresses consist of:</p><ul><li>The first IP address in the CIDR (the network address)</li><li>The last IP address in the CIDR (the broadcast address)</li><li>The first host address in the CIDR (the subnet default gateway address)</li></ul><p>For example, in a subnet with CIDR 192.168.0.0/24, these addresses are reserved:</p><ul><li>192.168.0.0 (the network address)</li><li>192.168.0.255 (the broadcast address)</li><li>192.168.0.1 (the subnet default gateway address)</li></ul><p>The remaining addresses in the CIDR (192.168.0.2 to 192.168.0.254) are available for use.</p><h2 id="creating-automation-with-events" tabindex="-1">Creating Automation with Events <a class="header-anchor" href="#creating-automation-with-events" aria-label="Permalink to &quot;Creating Automation with Events&quot;">​</a></h2><p>You can create automation based on state changes for Oracle Cloud Infrastructure resources by using event types, rules, and actions. For more information, see <a href="https://docs.oracle.com/iaas/Content/Events/Concepts/eventsoverview.htm" target="_blank" rel="noreferrer">Overview of Events</a>.</p><h2 id="resource-identifiers" tabindex="-1">Resource Identifiers <a class="header-anchor" href="#resource-identifiers" aria-label="Permalink to &quot;Resource Identifiers&quot;">​</a></h2><p>Most types of Oracle Cloud Infrastructure resources have a unique, Oracle-assigned identifier called an Oracle Cloud ID (OCID). For information about the OCID format and other ways to identify your resources, see <a href="https://docs.oracle.com/iaas/Content/General/Concepts/identifiers.htm" target="_blank" rel="noreferrer">Resource Identifiers</a>.</p><h2 id="ways-to-access-oracle-cloud-infrastructure" tabindex="-1">Ways to Access Oracle Cloud Infrastructure <a class="header-anchor" href="#ways-to-access-oracle-cloud-infrastructure" aria-label="Permalink to &quot;Ways to Access Oracle Cloud Infrastructure&quot;">​</a></h2><p>You can access Oracle Cloud Infrastructure (OCI) by using the <a href="https://docs.oracle.com/iaas/Content/GSG/Tasks/signingin_topic-Signing_In_for_the_First_Time.htm" target="_blank" rel="noreferrer">Console</a> (a browser-based interface), <a href="https://docs.oracle.com/iaas/Content/API/Concepts/usingapi.htm" target="_blank" rel="noreferrer">REST API</a>, or <a href="https://docs.oracle.com/iaas/Content/API/Concepts/cliconcepts.htm" target="_blank" rel="noreferrer">OCI CLI</a>. Instructions for using the Console, API, and CLI are included in topics throughout this documentation. For a list of available SDKs, see <a href="https://docs.oracle.com/iaas/Content/API/Concepts/sdks.htm" target="_blank" rel="noreferrer">Software Development Kits and Command Line Interface</a>.</p><p>To access the <a href="https://cloud.oracle.com/" target="_blank" rel="noreferrer">Console</a>, you must use a <a href="https://docs.oracle.com/iaas/Content/GSG/Tasks/signinginIdentityDomain.htm#supported-browsers" target="_blank" rel="noreferrer">supported browser</a>. To go to the Console sign-in page, open the navigation menu at the top of this page and select <strong>Infrastructure Console</strong>. You are prompted to enter your cloud tenant, your user name, and your password.</p><p>For general information about using the API, see <a href="https://docs.oracle.com/iaas/Content/API/Concepts/usingapi.htm" target="_blank" rel="noreferrer">REST APIs</a>.</p><h2 id="authentication-and-authorization" tabindex="-1">Authentication and Authorization <a class="header-anchor" href="#authentication-and-authorization" aria-label="Permalink to &quot;Authentication and Authorization&quot;">​</a></h2><p>Each service in Oracle Cloud Infrastructure integrates with IAM for authentication and authorization, for all interfaces (the Console, SDK or CLI, and REST API).</p><p>An administrator in an organization needs to set up <strong>groups</strong>, <strong>compartments</strong>, and <strong>policies</strong> that control which users can access which services, which resources, and the type of access. For example, the policies control who can create new users, create and manage the cloud network, create instances, create buckets, download objects, and so on. For more information, see <a href="https://docs.oracle.com/iaas/Content/Identity/domains/overview.htm" target="_blank" rel="noreferrer">Managing Identity Domains</a>. For specific details about writing policies for each of the different services, see <a href="https://docs.oracle.com/iaas/Content/Identity/Reference/policyreference.htm" target="_blank" rel="noreferrer">Policy Reference</a>.</p><p>If you&#39;re a regular user (not an administrator) who needs to use the Oracle Cloud Infrastructure resources that the company owns, contact an administrator to set up a user ID for you. The administrator can confirm which compartment or compartments you can use.</p><h2 id="iam-policies-for-networking" tabindex="-1">IAM Policies for Networking <a class="header-anchor" href="#iam-policies-for-networking" aria-label="Permalink to &quot;IAM Policies for Networking&quot;">​</a></h2><p>The most straightforward approach to granting access to Networking is the policy listed in <a href="https://docs.oracle.com/iaas/Content/Identity/Concepts/commonpolicies.htm#network-admins-manage-cloud-network" target="_blank" rel="noreferrer">Let network admins manage a cloud network</a>. It covers the cloud network and all the other Networking components (subnets, security lists, route tables, gateways, and so on). To also give network admins the ability to create instances (to test network connectivity), see <a href="https://docs.oracle.com/iaas/Content/Identity/Concepts/commonpolicies.htm#launch-instances" target="_blank" rel="noreferrer">Let users launch compute instances</a>.</p><p>If you&#39;re new to policies, see <a href="https://docs.oracle.com/iaas/Content/Identity/domains/overview.htm" target="_blank" rel="noreferrer">Managing Identity Domains</a> and <a href="https://docs.oracle.com/iaas/Content/Identity/Concepts/commonpolicies.htm" target="_blank" rel="noreferrer">Common Policies</a>.</p><p>For reference material for writing more detailed policies for Networking, see <a href="https://docs.oracle.com/iaas/Content/Identity/policyreference/corepolicyreference.htm" target="_blank" rel="noreferrer">Details for the Core Services</a>.</p><h3 id="individual-resource-types" tabindex="-1">Individual Resource-Types <a class="header-anchor" href="#individual-resource-types" aria-label="Permalink to &quot;Individual Resource-Types&quot;">​</a></h3><p>You can write policies that focus on individual resource-types (for example, security lists only) instead of the broader <code>virtual-network-family</code>. The <code>instance-family</code> resource-type also includes several permissions for VNICs, which reside in a subnet but attach to an instance. For more information, see <a href="https://docs.oracle.com/iaas/Content/Identity/policyreference/corepolicyreference.htm#Core" target="_blank" rel="noreferrer">Details for Verb + Resource-Type Combinations</a> and <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVNICs.htm" target="_blank" rel="noreferrer">Virtual Network Interface Cards (VNICs)</a>.</p><p>A resource-type called <code>local-peering-gateways</code> is included within <code>virtual-network-family</code> and includes two other resource-types related to local VCN peering (within region):</p><ul><li><code>local-peering-from</code></li><li><code>local-peering-to</code></li></ul><p>The <code>local-peering-gateways</code> resource-type covers all permissions related to local peering gateways (LPGs). The <code>local-peering-from</code> and <code>local-peering-to</code> resource-types are for granting permission to connect two LPGs and define a peering relationship within a single region. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/drg-iam.htm#scenario_m__local-LPG" target="_blank" rel="noreferrer">Local Peering using an LPG (VCNs in the Same Tenancy)</a> or <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/drg-iam.htm#scenario_m__local-LPG-xten" target="_blank" rel="noreferrer">Local Peering using an LPG (VCNs in Different Tenancies)</a>.</p><p>Similarly, a resource-type called <code>remote-peering-connections</code> is included within <code>virtual-network-family</code> and includes two other resource-types related to remote VCN peering (across regions):</p><ul><li><code>remote-peering-from</code></li><li><code>remote-peering-to</code></li></ul><p>The <code>remote-peering-connections</code> resource-type covers all permissions related to remote peering connections (RPCs). The <code>remote-peering-from</code> and <code>remote-peering-to</code> resource-types are for granting permission to connect two RPCs and define a peering relationship across regions. For more information, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/drg-iam.htm#scenario_m__remote-peer-policy" target="_blank" rel="noreferrer">Remote Peering with a Legacy DRG</a> and <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/drg-iam.htm#scenario_m__IAM_cross-tenancy" target="_blank" rel="noreferrer">Remote Peering with an Upgraded DRG</a>.</p><h3 id="nuances-of-different-verbs" tabindex="-1">Nuances of Different Verbs <a class="header-anchor" href="#nuances-of-different-verbs" aria-label="Permalink to &quot;Nuances of Different Verbs&quot;">​</a></h3><p>You can write policies that limit the level of access by using a different policy verb (<code>manage</code> instead of <code>use</code>, and so on). If you do, here are some nuances to understand about the policy verbs for Networking.</p><p>Be aware that the <code>inspect</code> verb not only returns general information about the cloud network&#39;s components (for example, the name and OCID of a security list, or of a route table). It also includes the contents of the component (for example, the actual rules in the security list, the routes in the route table, and so on).</p><p>Also, the following types of abilities are available only with the <code>manage</code> verb, not the <code>use</code> verb:</p><ul><li>Update (enable/disable) <code>internet-gateways</code></li><li>Update <code>security-lists</code></li><li>Update <code>route-tables</code></li><li>Update <code>dhcp-options</code></li><li>Attach a Dynamic Routing Gateway (DRG) to a Virtual Cloud Network (VCN)</li><li>Create an IPSec connection between a DRG and customer-premises equipment (CPE)</li><li>Peer VCNs</li></ul><blockquote><p><strong>Warning</strong></p><p>Each VCN has various components that directly affect the behavior of the network (route tables, security lists, DHCP options, Internet Gateway, and so on). When you create one of these components, you establish a relationship between that component and the VCN, which means you must be allowed in a policy to both create the component and manage the VCN itself. However, the ability to update that component (to change the route rules, security list rules, and so on) does not require permission to manage the VCN itself, even though changing that component can directly affect the behavior of the network. This design enables least-privilege policies but requires trust in users who can update components.</p></blockquote><p>For more information about policy verbs, see <a href="https://docs.oracle.com/iaas/Content/Identity/Concepts/policies.htm#Policy" target="_blank" rel="noreferrer">Policy Basics</a>.</p><h3 id="peering-policies" tabindex="-1">Peering Policies <a class="header-anchor" href="#peering-policies" aria-label="Permalink to &quot;Peering Policies&quot;">​</a></h3><p>For policies used in connecting a DRG to VCNs and DRGs in other regions and tenancies, see <a href="https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/drg-iam.htm" target="_blank" rel="noreferrer">IAM Policies for Routing Between VCNs</a>.</p><h2 id="limits-on-networking-components" tabindex="-1">Limits on Networking Components <a class="header-anchor" href="#limits-on-networking-components" aria-label="Permalink to &quot;Limits on Networking Components&quot;">​</a></h2><p>See <a href="https://docs.oracle.com/iaas/Content/General/Concepts/servicelimits.htm#network_limits" target="_blank" rel="noreferrer">Networking Limits</a> for a list of applicable service limits, and <a href="https://docs.oracle.com/iaas/Content/General/Concepts/servicelimits-request-increase.htm" target="_blank" rel="noreferrer">Requesting a Service Limit Increase</a> for instructions on requesting a limit increase.</p>',127)])])}const f=t(s,[["render",i]]);export{m as __pageData,f as default};
